{
  "name": "Fancy Flap Bird",
  "description": "A high-fidelity Flappy Bird clone featuring the 'Agent Bird' with a hat, pixelated environments, and smooth performance using React and Canvas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameStatus {
  START = 'START',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER'
}

export interface Bird {
  y: number;
  velocity: number;
  rotation: number;
  width: number;
  height: number;
}

export interface Pipe {
  x: number;
  topHeight: number;
  passed: boolean;
}

export interface GameState {
  status: GameStatus;
  score: number;
  highScore: number;
}

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;
export const GRAVITY = 0.35;
export const JUMP_STRENGTH = -7;
export const PIPE_SPEED = 3;
export const PIPE_SPAWN_RATE = 100; // frames
export const PIPE_WIDTH = 70;
export const PIPE_GAP = 160;

// Asset URLs - Using high quality placeholders matching the requested style
export const ASSETS = {
  BIRD_AGENT: 'https://i.ibb.co/LzqX7N4/blue-bird-hat.png', // Fallback placeholder for the hat bird
  BACKGROUND: 'https://i.ibb.co/PZ9v6pW/pixel-clouds.png',
  PIPE_HEAD: 'https://i.ibb.co/m0f6qPq/pipe-head.png',
  PIPE_BODY: 'https://i.ibb.co/S3hN3M6/pipe-body.png'
};

// Data URIs for the specific requested images to ensure they load
// Note: In a real app we'd use local files, but here we'll use hosted versions or high-res fallbacks
export const AGENT_BIRD_SRC = "https://images.clutchpoints.com/posts/750820/750820.jpg"; // Based on prompt visual
export const CLOUD_BG_SRC = "https://i.pinimg.com/originals/02/7e/63/027e638b936d5f75f782c5f10255c276.png";

import React from 'react';
import Game from './components/Game';

const App: React.FC = () => {
  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-slate-900 p-4">
      <div className="relative shadow-2xl border-8 border-slate-800 rounded-3xl overflow-hidden bg-sky-300">
        <Game />
        <div className="absolute top-4 left-0 right-0 pointer-events-none flex justify-center">
          <h1 className="text-white text-xs drop-shadow-md opacity-50 tracking-tighter">
            AGENT FLAP v1.0
          </h1>
        </div>
      </div>

      <div className="mt-8 text-white text-center max-w-sm">
        <p className="text-[10px] leading-relaxed opacity-70">
          PRESS <span className="text-yellow-400 font-bold">SPACE</span> OR <span className="text-yellow-400 font-bold">CLICK</span> TO FLAP
        </p>
        <p className="mt-2 text-[8px] opacity-40">
          Avoid the pipes and keep Agent Bird in the air!
        </p>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameStatus, Bird, Pipe } from '../types';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  GRAVITY, 
  JUMP_STRENGTH, 
  PIPE_SPEED, 
  PIPE_SPAWN_RATE, 
  PIPE_WIDTH, 
  PIPE_GAP 
} from '../constants';

const Game: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [gameState, setGameState] = useState<GameStatus>(GameStatus.START);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(() => {
    const saved = localStorage.getItem('flap_highscore');
    return saved ? parseInt(saved, 10) : 0;
  });

  // Assets
  const birdImg = useRef<HTMLImageElement | null>(null);
  const bgImg = useRef<HTMLImageElement | null>(null);

  // Game Logic State (Mutable refs for performance in loop)
  const bird = useRef<Bird>({
    y: CANVAS_HEIGHT / 2,
    velocity: 0,
    rotation: 0,
    width: 54, // Proportional to requested image
    height: 44
  });
  const pipes = useRef<Pipe[]>([]);
  const frameCount = useRef(0);
  const animationFrameId = useRef<number>();
  const bgX = useRef(0);

  // Initialize Assets
  useEffect(() => {
    const bird = new Image();
    // Using a clear version of the Agent Bird image
    bird.src = "https://i.ibb.co/LzqX7N4/blue-bird-hat.png";
    birdImg.current = bird;

    const bg = new Image();
    bg.src = "https://i.ibb.co/PZ9v6pW/pixel-clouds.png";
    bgImg.current = bg;
  }, []);

  const resetGame = useCallback(() => {
    bird.current = {
      y: CANVAS_HEIGHT / 2,
      velocity: 0,
      rotation: 0,
      width: 54,
      height: 44
    };
    pipes.current = [];
    frameCount.current = 0;
    setScore(0);
    setGameState(GameStatus.PLAYING);
  }, []);

  const flap = useCallback(() => {
    if (gameState === GameStatus.START) {
      resetGame();
    } else if (gameState === GameStatus.PLAYING) {
      bird.current.velocity = JUMP_STRENGTH;
    } else if (gameState === GameStatus.GAME_OVER) {
      resetGame();
    }
  }, [gameState, resetGame]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' || e.code === 'ArrowUp') {
        e.preventDefault();
        flap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [flap]);

  const drawPipe = (ctx: CanvasRenderingContext2D, pipe: Pipe) => {
    // Pipe styling (Green gradient pixel look)
    const renderPipePart = (x: number, y: number, w: number, h: number, isTop: boolean) => {
      const gradient = ctx.createLinearGradient(x, y, x + w, y);
      gradient.addColorStop(0, '#73bf2e');
      gradient.addColorStop(0.3, '#94e044');
      gradient.addColorStop(0.7, '#73bf2e');
      gradient.addColorStop(1, '#538018');

      ctx.fillStyle = gradient;
      ctx.fillRect(x, y, w, h);

      // Outline
      ctx.strokeStyle = '#2d4d0c';
      ctx.lineWidth = 3;
      ctx.strokeRect(x, y, w, h);

      // Pipe Lip
      const lipHeight = 24;
      const lipX = x - 5;
      const lipW = w + 10;
      const lipY = isTop ? y + h - lipHeight : y;

      ctx.fillStyle = gradient;
      ctx.fillRect(lipX, lipY, lipW, lipHeight);
      ctx.strokeRect(lipX, lipY, lipW, lipHeight);
    };

    // Top Pipe
    renderPipePart(pipe.x, 0, PIPE_WIDTH, pipe.topHeight, true);
    // Bottom Pipe
    renderPipePart(pipe.x, pipe.topHeight + PIPE_GAP, PIPE_WIDTH, CANVAS_HEIGHT - (pipe.topHeight + PIPE_GAP), false);
  };

  const update = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear
    ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Draw Background (Scrolling Clouds)
    if (bgImg.current && bgImg.current.complete) {
      bgX.current -= 0.5;
      if (bgX.current <= -CANVAS_WIDTH) bgX.current = 0;
      ctx.drawImage(bgImg.current, bgX.current, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.drawImage(bgImg.current, bgX.current + CANVAS_WIDTH, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    } else {
      ctx.fillStyle = '#70c5ce';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    }

    if (gameState === GameStatus.PLAYING) {
      // Update Bird
      bird.current.velocity += GRAVITY;
      bird.current.y += bird.current.velocity;
      bird.current.rotation = Math.min(Math.PI / 4, Math.max(-Math.PI / 4, bird.current.velocity * 0.1));

      // Floor/Ceiling Collision
      if (bird.current.y + bird.current.height / 2 >= CANVAS_HEIGHT) {
        setGameState(GameStatus.GAME_OVER);
      }
      if (bird.current.y <= 0) {
        bird.current.y = 0;
        bird.current.velocity = 0;
      }

      // Update Pipes
      if (frameCount.current % PIPE_SPAWN_RATE === 0) {
        const minHeight = 50;
        const maxHeight = CANVAS_HEIGHT - PIPE_GAP - 50;
        const topHeight = Math.floor(Math.random() * (maxHeight - minHeight + 1)) + minHeight;
        pipes.current.push({ x: CANVAS_WIDTH, topHeight, passed: false });
      }

      for (let i = pipes.current.length - 1; i >= 0; i--) {
        const p = pipes.current[i];
        p.x -= PIPE_SPEED;

        // Collision Check
        const bx = 80; // Bird fixed X
        const by = bird.current.y;
        const bw = bird.current.width - 10;
        const bh = bird.current.height - 10;

        if (
          bx + bw / 2 > p.x && 
          bx - bw / 2 < p.x + PIPE_WIDTH
        ) {
          if (by - bh / 2 < p.topHeight || by + bh / 2 > p.topHeight + PIPE_GAP) {
            setGameState(GameStatus.GAME_OVER);
          }
        }

        // Score Check
        if (!p.passed && p.x + PIPE_WIDTH < bx) {
          p.passed = true;
          setScore(prev => {
            const newScore = prev + 1;
            if (newScore > highScore) {
              setHighScore(newScore);
              localStorage.setItem('flap_highscore', newScore.toString());
            }
            return newScore;
          });
        }

        // Remove off-screen pipes
        if (p.x + PIPE_WIDTH < 0) {
          pipes.current.splice(i, 1);
        }
      }

      frameCount.current++;
    }

    // Draw Pipes
    pipes.current.forEach(p => drawPipe(ctx, p));

    // Draw Bird
    ctx.save();
    ctx.translate(80, bird.current.y);
    ctx.rotate(bird.current.rotation);
    if (birdImg.current && birdImg.current.complete) {
      ctx.drawImage(
        birdImg.current, 
        -bird.current.width / 2, 
        -bird.current.height / 2, 
        bird.current.width, 
        bird.current.height
      );
    } else {
      // Fallback Circle
      ctx.beginPath();
      ctx.fillStyle = '#ffd93b';
      ctx.arc(0, 0, 20, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();

    // UI Overlays
    if (gameState === GameStatus.START) {
      ctx.fillStyle = 'rgba(0,0,0,0.4)';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '24px "Press Start 2P"';
      ctx.fillText('READY?', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 20);
      ctx.font = '10px "Press Start 2P"';
      ctx.fillText('CLICK TO START', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 30);
    }

    if (gameState === GameStatus.GAME_OVER) {
      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '20px "Press Start 2P"';
      ctx.fillText('GAME OVER', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 60);

      ctx.font = '12px "Press Start 2P"';
      ctx.fillStyle = '#FFD700';
      ctx.fillText(`SCORE: ${score}`, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillText(`BEST: ${highScore}`, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 30);

      ctx.font = '10px "Press Start 2P"';
      ctx.fillText('CLICK TO RESTART', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 90);
    }

    // Constant Score Display
    if (gameState === GameStatus.PLAYING) {
      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '32px "Press Start 2P"';
      ctx.strokeStyle = 'black';
      ctx.lineWidth = 6;
      ctx.strokeText(score.toString(), CANVAS_WIDTH / 2, 80);
      ctx.fillText(score.toString(), CANVAS_WIDTH / 2, 80);
    }

    animationFrameId.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    animationFrameId.current = requestAnimationFrame(update);
    return () => {
      if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
    };
  }, [gameState, score, highScore]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onClick={flap}
      className="cursor-pointer block"
    />
  );
};

export default Game;

export const CANVAS_WIDTH = 400;
export const CANVAS_HEIGHT = 600;
export const GRAVITY = 0.35;
export const JUMP_STRENGTH = -7;
export const PIPE_SPEED = 3;
export const PIPE_SPAWN_RATE = 100; // frames
export const PIPE_WIDTH = 70;
export const PIPE_GAP = 160;

// Asset URLs
export const ASSETS = {
  BIRD_AGENT: 'https://i.ibb.co/LzqX7N4/blue-bird-hat.png',
  BACKGROUND: 'https://i.ibb.co/PZ9v6pW/pixel-clouds.png',
  PIPE_HEAD: 'https://i.ibb.co/m0f6qPq/pipe-head.png',
  PIPE_BODY: 'https://i.ibb.co/S3hN3M6/pipe-body.png'
};

// Data URIs or direct links for assets
// Updated AGENT_BIRD_SRC to a dedicated sprite of a bird with a hat
export const AGENT_BIRD_SRC = "https://i.ibb.co/LzqX7N4/blue-bird-hat.png"; 
export const CLOUD_BG_SRC = "https://i.pinimg.com/originals/02/7e/63/027e638b936d5f75f782c5f10255c276.png";

