  const bird = useRef<Bird>({
    y: CANVAS_HEIGHT / 2,
    velocity: 0,
    rotation: 0,
    width: 60, // Adjusted for the hat sprite
    height: 52  // Slightly taller to accommodate the hat
  });
  const pipes = useRef<Pipe[]>([]);
  const frameCount = useRef(0);
  const animationFrameId = useRef<number>();
  const bgX = useRef(0);

