          pipes.current.splice(i, 1);
        }
      }

      frameCount.current++;
    }

    pipes.current.forEach(p => drawPipe(ctx, p));

    ctx.save();
    // Adjusted y position slightly when rendering to ensure the bird body is centered, 
    // even if the hat adds height to the top of the image.
    ctx.translate(80, bird.current.y);
    ctx.rotate(bird.current.rotation);
    if (birdImg.current && birdImg.current.complete) {
      ctx.drawImage(
