export const AGENT_BIRD_SRC = "https://i.ibb.co/LzqX7N4/blue-bird-hat.png"; 
export const CLOUD_BG_SRC = "https://i.ibb.co/PZ9v6pW/pixel-clouds.png";

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameStatus, Bird, Pipe } from '../types';
import { 
  CANVAS_WIDTH, 
  CANVAS_HEIGHT, 
  GRAVITY, 
  JUMP_STRENGTH, 
  PIPE_SPEED, 
  PIPE_SPAWN_RATE, 
  PIPE_WIDTH, 
  PIPE_GAP,
  AGENT_BIRD_SRC,
  ASSETS
} from '../constants';

const Game: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [gameState, setGameState] = useState<GameStatus>(GameStatus.START);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(() => {
    const saved = localStorage.getItem('flap_highscore');
    return saved ? parseInt(saved, 10) : 0;
  });

  // Assets
  const birdImg = useRef<HTMLImageElement | null>(null);
  const bgImg = useRef<HTMLImageElement | null>(null);

  // Game Logic State (Mutable refs for high performance)
  const bird = useRef<Bird>({
    y: CANVAS_HEIGHT / 2,
    velocity: 0,
    rotation: 0,
    width: 64,  // Visual width
    height: 56  // Visual height (including hat)
  });

  const pipes = useRef<Pipe[]>([]);
  const frameCount = useRef(0);
  const animationFrameId = useRef<number>();
  const bgX = useRef(0);

  // Initialize Assets
  useEffect(() => {
    const birdImage = new Image();
    birdImage.src = AGENT_BIRD_SRC;
    birdImg.current = birdImage;

    const bgImage = new Image();
    bgImage.src = ASSETS.BACKGROUND;
    bgImg.current = bgImage;
  }, []);

  const resetGame = useCallback(() => {
    bird.current = {
      y: CANVAS_HEIGHT / 2,
      velocity: 0,
      rotation: 0,
      width: 64,
      height: 56
    };
    pipes.current = [];
    frameCount.current = 0;
    setScore(0);
    setGameState(GameStatus.PLAYING);
  }, []);

  const flap = useCallback(() => {
    if (gameState === GameStatus.START) {
      resetGame();
    } else if (gameState === GameStatus.PLAYING) {
      bird.current.velocity = JUMP_STRENGTH;
    } else if (gameState === GameStatus.GAME_OVER) {
      resetGame();
    }
  }, [gameState, resetGame]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' || e.code === 'ArrowUp') {
        e.preventDefault();
        flap();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [flap]);

  const drawPipe = (ctx: CanvasRenderingContext2D, pipe: Pipe) => {
    const renderPipePart = (x: number, y: number, w: number, h: number, isTop: boolean) => {
      // Pipe Main Gradient
      const gradient = ctx.createLinearGradient(x, y, x + w, y);
      gradient.addColorStop(0, '#55a02e');
      gradient.addColorStop(0.2, '#73bf2e');
      gradient.addColorStop(0.4, '#94e044');
      gradient.addColorStop(0.8, '#73bf2e');
      gradient.addColorStop(1, '#437018');

      ctx.fillStyle = gradient;
      ctx.fillRect(x, y, w, h);

      // Highlight line
      ctx.fillStyle = 'rgba(255,255,255,0.2)';
      ctx.fillRect(x + 10, y, 4, h);

      // Dark shadow line
      ctx.fillStyle = 'rgba(0,0,0,0.1)';
      ctx.fillRect(x + w - 15, y, 6, h);

      // Outline
      ctx.strokeStyle = '#2d4d0c';
      ctx.lineWidth = 3;
      ctx.strokeRect(x, y, w, h);

      // Pipe Lip (The wide part)
      const lipHeight = 28;
      const lipX = x - 6;
      const lipW = w + 12;
      const lipY = isTop ? y + h - lipHeight : y;

      ctx.fillStyle = gradient;
      ctx.fillRect(lipX, lipY, lipW, lipHeight);
      ctx.strokeRect(lipX, lipY, lipW, lipHeight);

      // Highlight on lip
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.fillRect(lipX + 12, lipY + 4, 6, lipHeight - 8);
    };

    // Draw top and bottom segments
    renderPipePart(pipe.x, 0, PIPE_WIDTH, pipe.topHeight, true);
    renderPipePart(pipe.x, pipe.topHeight + PIPE_GAP, PIPE_WIDTH, CANVAS_HEIGHT - (pipe.topHeight + PIPE_GAP), false);
  };

  const update = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 1. CLEAR
    ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 2. BACKGROUND (Parallax)
    if (bgImg.current && bgImg.current.complete) {
      bgX.current -= 0.6; // Slow scroll for depth
      if (bgX.current <= -CANVAS_WIDTH) bgX.current = 0;
      ctx.drawImage(bgImg.current, bgX.current, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.drawImage(bgImg.current, bgX.current + CANVAS_WIDTH, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    } else {
      ctx.fillStyle = '#70c5ce';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    }

    // 3. GAME LOGIC
    if (gameState === GameStatus.PLAYING) {
      // Bird Physics
      bird.current.velocity += GRAVITY;
      bird.current.y += bird.current.velocity;

      // Smooth Rotation based on velocity
      const targetRotation = Math.min(Math.PI / 4, Math.max(-Math.PI / 6, bird.current.velocity * 0.08));
      bird.current.rotation += (targetRotation - bird.current.rotation) * 0.2;

      // Death by Floor/Ceiling
      if (bird.current.y + bird.current.height / 3 >= CANVAS_HEIGHT) {
        setGameState(GameStatus.GAME_OVER);
      }
      if (bird.current.y <= 0) {
        bird.current.y = 0;
        bird.current.velocity = 0;
      }

      // Pipe Spawning
      if (frameCount.current % PIPE_SPAWN_RATE === 0) {
        const minHeight = 80;
        const maxHeight = CANVAS_HEIGHT - PIPE_GAP - 120;
        const topHeight = Math.floor(Math.random() * (maxHeight - minHeight + 1)) + minHeight;
        pipes.current.push({ x: CANVAS_WIDTH, topHeight, passed: false });
      }

      // Pipe Updates & Collisions
      for (let i = pipes.current.length - 1; i >= 0; i--) {
        const p = pipes.current[i];
        p.x -= PIPE_SPEED;

        // Collision Check (Fair Hitbox)
        const bx = 80;
        const by = bird.current.y + 4; // Shift hitbox down slightly to center on body
        const bw = 34; // Tight body hitbox
        const bh = 34; 

        if (bx + bw / 2 > p.x && bx - bw / 2 < p.x + PIPE_WIDTH) {
          if (by - bh / 2 < p.topHeight || by + bh / 2 > p.topHeight + PIPE_GAP) {
            setGameState(GameStatus.GAME_OVER);
          }
        }

        // Scoring
        if (!p.passed && p.x + PIPE_WIDTH < bx) {
          p.passed = true;
          setScore(prev => {
            const newScore = prev + 1;
            if (newScore > highScore) {
              setHighScore(newScore);
              localStorage.setItem('flap_highscore', newScore.toString());
            }
            return newScore;
          });
        }

        // Cleanup
        if (p.x + PIPE_WIDTH < -100) {
          pipes.current.splice(i, 1);
        }
      }

      frameCount.current++;
    }

    // 4. DRAW PIPES
    pipes.current.forEach(p => drawPipe(ctx, p));

    // 5. DRAW BIRD
    ctx.save();
    ctx.translate(80, bird.current.y);
    ctx.rotate(bird.current.rotation);
    if (birdImg.current && birdImg.current.complete) {
      ctx.drawImage(
        birdImg.current, 
        -bird.current.width / 2, 
        -bird.current.height / 2, 
        bird.current.width, 
        bird.current.height
      );
    } else {
      ctx.beginPath();
      ctx.fillStyle = '#ffd93b';
      ctx.arc(0, 0, 18, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();

    // 6. UI OVERLAYS
    if (gameState === GameStatus.START) {
      ctx.fillStyle = 'rgba(0,0,0,0.5)';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '24px "Press Start 2P"';
      ctx.fillText('READY?', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 40);

      ctx.font = '10px "Press Start 2P"';
      ctx.fillText('CLICK OR SPACE TO FLAP', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 20);
    }

    if (gameState === GameStatus.GAME_OVER) {
      ctx.fillStyle = 'rgba(0,0,0,0.7)';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '20px "Press Start 2P"';
      ctx.fillText('GAME OVER', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 80);

      ctx.font = '14px "Press Start 2P"';
      ctx.fillStyle = '#FFD700';
      ctx.fillText(`SCORE: ${score}`, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 10);
      ctx.fillStyle = 'white';
      ctx.fillText(`BEST: ${highScore}`, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 30);

      ctx.font = '10px "Press Start 2P"';
      ctx.fillText('CLICK TO TRY AGAIN', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 100);
    }

    // Constant Score Display
    if (gameState === GameStatus.PLAYING) {
      ctx.fillStyle = 'white';
      ctx.textAlign = 'center';
      ctx.font = '36px "Press Start 2P"';
      ctx.strokeStyle = 'black';
      ctx.lineWidth = 8;
      ctx.lineJoin = 'round';
      ctx.strokeText(score.toString(), CANVAS_WIDTH / 2, 100);
      ctx.fillText(score.toString(), CANVAS_WIDTH / 2, 100);
    }

    animationFrameId.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    animationFrameId.current = requestAnimationFrame(update);
    return () => {
      if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
    };
  }, [gameState, score, highScore]);

  return (
    <canvas
      ref={canvasRef}
      width={CANVAS_WIDTH}
      height={CANVAS_HEIGHT}
      onClick={flap}
      className="cursor-pointer block"
    />
  );
};

export default Game;

